import{_ as n,o as r,c as i,ag as l}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Rechnungen","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/invoices.md","filePath":"de/features/invoices.md"}'),a={name:"de/features/invoices.md"};function t(s,e,h,o,u,g){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="rechnungen" tabindex="-1">Rechnungen <a class="header-anchor" href="#rechnungen" aria-label="Permalink to &quot;Rechnungen&quot;">​</a></h1><p>Rechnungen stehen im Mittelpunkt von MyCompanyDesk. Erstellen Sie professionelle Rechnungen, versenden Sie sie mit Zahlungslinks an Kunden und verfolgen Sie Zahlungen bis zum Abschluss.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die Rechnungsseite zeigt alle Ihre Rechnungen mit Filter- und Suchfunktionen. Verwenden Sie die Status-Tabs für eine schnelle Ansicht:</p><ul><li><strong>Alle</strong> — Jede Rechnung</li><li><strong>Entwurf</strong> — Erstellt, aber nicht gesendet</li><li><strong>Gesendet</strong> — An Kunden zugestellt</li><li><strong>Überfällig</strong> — Fälligkeitsdatum überschritten, unbezahlt</li><li><strong>Bezahlt</strong> — Zahlung eingegangen</li><li><strong>Storniert</strong> — Stornierte Rechnungen</li></ul><h2 id="rechnung-erstellen" tabindex="-1">Rechnung erstellen <a class="header-anchor" href="#rechnung-erstellen" aria-label="Permalink to &quot;Rechnung erstellen&quot;">​</a></h2><h3 id="vollstandiges-formular" tabindex="-1">Vollständiges Formular <a class="header-anchor" href="#vollstandiges-formular" aria-label="Permalink to &quot;Vollständiges Formular&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Rechnungen &gt; Neue Rechnung</strong></li><li>Wählen oder erstellen Sie einen <strong>Kunden</strong></li><li>Fügen Sie <strong>Positionen</strong> mit Beschreibung, Menge, Einzelpreis und USt.-Satz hinzu</li><li>Legen Sie das <strong>Rechnungsdatum</strong> und das <strong>Fälligkeitsdatum</strong> fest</li><li>Fügen Sie optionale <strong>Anmerkungen</strong> oder <strong>interne Bemerkungen</strong> hinzu</li><li>Klicken Sie auf <strong>Speichern</strong>, um einen Entwurf zu erstellen</li></ol><h3 id="schnellerfassung" tabindex="-1">Schnellerfassung <a class="header-anchor" href="#schnellerfassung" aria-label="Permalink to &quot;Schnellerfassung&quot;">​</a></h3><p>Für eine schnellere Erstellung:</p><ol><li>Klicken Sie auf die Schnellerfassungs-Schaltfläche auf der Rechnungsliste</li><li>Wählen Sie einen Kunden</li><li>Fügen Sie Positionen hinzu oder wählen Sie eine Vorlage</li><li>Speichern (und optional sofort versenden)</li></ol><h3 id="aus-einer-vorlage" tabindex="-1">Aus einer Vorlage <a class="header-anchor" href="#aus-einer-vorlage" aria-label="Permalink to &quot;Aus einer Vorlage&quot;">​</a></h3><ol><li>Klicken Sie beim Erstellen einer neuen Rechnung auf <strong>Vorlage verwenden</strong></li><li>Wählen Sie eine gespeicherte Vorlage</li><li>Alle Positionen sind vorausgefüllt — passen Sie sie nach Bedarf an</li><li>Speichern und versenden</li></ol><h2 id="rechnungsdetails" tabindex="-1">Rechnungsdetails <a class="header-anchor" href="#rechnungsdetails" aria-label="Permalink to &quot;Rechnungsdetails&quot;">​</a></h2><p>Jede Rechnung hat eine Detailseite, die zeigt:</p><ul><li>Kundeninformationen</li><li>Positionen mit Zwischensummen</li><li>USt.-Aufschlüsselung</li><li>Gesamtbetrag</li><li>Status und Verlauf</li><li>Zahlungslink (falls gesendet)</li></ul><h2 id="aktionen" tabindex="-1">Aktionen <a class="header-anchor" href="#aktionen" aria-label="Permalink to &quot;Aktionen&quot;">​</a></h2><h3 id="senden" tabindex="-1">Senden <a class="header-anchor" href="#senden" aria-label="Permalink to &quot;Senden&quot;">​</a></h3><p>Senden Sie die Rechnung per E-Mail an Ihren Kunden. Die E-Mail enthält:</p><ul><li>Eine anpassbare Nachricht (basierend auf Ihrer E-Mail-Vorlage)</li><li>Die Rechnungs-PDF als Anhang</li><li>Einen Zahlungslink für die Online-Zahlung</li></ul><h3 id="pdf-herunterladen" tabindex="-1">PDF herunterladen <a class="header-anchor" href="#pdf-herunterladen" aria-label="Permalink to &quot;PDF herunterladen&quot;">​</a></h3><p>Laden Sie die Rechnung als professionell formatiertes PDF-Dokument herunter. Das PDF enthält Ihr Firmenlogo, Ihre Markenfarben und alle Rechnungsdetails.</p><h3 id="als-bezahlt-markieren" tabindex="-1">Als bezahlt markieren <a class="header-anchor" href="#als-bezahlt-markieren" aria-label="Permalink to &quot;Als bezahlt markieren&quot;">​</a></h3><p>Bestätigen Sie die Zahlung manuell, wenn ein Kunde per Banküberweisung oder einer anderen Offline-Methode zahlt.</p><h3 id="stornieren" tabindex="-1">Stornieren <a class="header-anchor" href="#stornieren" aria-label="Permalink to &quot;Stornieren&quot;">​</a></h3><p>Stornieren Sie eine Rechnung, die nicht mehr bezahlt werden soll. Stornierte Rechnungen bleiben für Prüfungszwecke in Ihren Unterlagen.</p><h3 id="duplizieren" tabindex="-1">Duplizieren <a class="header-anchor" href="#duplizieren" aria-label="Permalink to &quot;Duplizieren&quot;">​</a></h3><p>Erstellen Sie eine Kopie einer bestehenden Rechnung — nützlich für wiederkehrende Abrechnungen an denselben Kunden.</p><h3 id="erinnerung-senden" tabindex="-1">Erinnerung senden <a class="header-anchor" href="#erinnerung-senden" aria-label="Permalink to &quot;Erinnerung senden&quot;">​</a></h3><p>Senden Sie eine Zahlungserinnerung für überfällige Rechnungen.</p><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><p>Wählen Sie mehrere Rechnungen aus der Liste, um Aktionen in großem Umfang durchzuführen:</p><ul><li><strong>Senden</strong> — Mehrere Entwurfsrechnungen gleichzeitig versenden</li><li><strong>Als bezahlt markieren</strong> — Zahlung für mehrere Rechnungen erfassen</li><li><strong>Archivieren</strong> — Rechnungen ins Archiv verschieben</li><li><strong>Löschen</strong> — Rechnungen dauerhaft entfernen</li></ul><h2 id="zahlungslinks" tabindex="-1">Zahlungslinks <a class="header-anchor" href="#zahlungslinks" aria-label="Permalink to &quot;Zahlungslinks&quot;">​</a></h2><p>Wenn Sie eine Rechnung versenden, wird ein eindeutiger Zahlungslink generiert. Ihr Kunde kann:</p><ol><li>Auf den Link in der E-Mail klicken</li><li>Die Rechnung im <strong>Kundenportal</strong> ansehen</li><li>Direkt online bezahlen</li></ol><p>Die Zahlung wird automatisch erfasst und der Rechnungsstatus wird auf <strong>Bezahlt</strong> aktualisiert.</p><h2 id="dokumenttypen" tabindex="-1">Dokumenttypen <a class="header-anchor" href="#dokumenttypen" aria-label="Permalink to &quot;Dokumenttypen&quot;">​</a></h2><p>Das Rechnungsmodul unterstützt mehrere Dokumenttypen:</p><ul><li><strong>Rechnung</strong> — Standard-Abrechnungsdokument</li><li><strong>Gutschrift</strong> — Anpassung für Rückerstattungen oder Korrekturen</li><li><strong>Erinnerung</strong> — Zahlungserinnerung für überfällige Rechnungen</li></ul><h2 id="filtern-und-suchen" tabindex="-1">Filtern und Suchen <a class="header-anchor" href="#filtern-und-suchen" aria-label="Permalink to &quot;Filtern und Suchen&quot;">​</a></h2><p>Verwenden Sie die Filterleiste, um Ihre Rechnungen einzugrenzen:</p><ul><li><strong>Status</strong> — Entwurf, Gesendet, Überfällig, Bezahlt, Storniert</li><li><strong>Kunde</strong> — Nach bestimmtem Kunden filtern</li><li><strong>Projekt</strong> — Nach verknüpftem Projekt filtern</li><li><strong>Datumsbereich</strong> — Nach Rechnungs- oder Fälligkeitsdatum filtern</li><li><strong>Suche</strong> — Nach Rechnungsnummer, Kundenname oder Beschreibung suchen</li></ul><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>Exportieren Sie Ihre Rechnungen als CSV zur Verwendung in Excel, Google Sheets oder Ihrer Buchhaltungssoftware.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV-Export erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Richten Sie Ihre <a href="/de/settings/email">E-Mail-Vorlagen</a> ein, bevor Sie Ihre erste Rechnung versenden</li><li>Verwenden Sie <a href="/de/features/recurring-invoices">wiederkehrende Rechnungen</a> für regelmäßige Abrechnungen</li><li>Prüfen Sie die <a href="/de/features/reports">Berichte</a>-Seite für Umsatzeinblicke</li><li>Aktivieren Sie <a href="/de/advanced/ai-features">KI-Vorschläge</a> für intelligente Beschreibungsverbesserungen</li></ul>',48)])])}const f=n(a,[["render",t]]);export{c as __pageData,f as default};
